// lib/services/s3_upload_service.dart
import 'dart:convert';
import 'dart:io';
import 'dart:typed_data';
import 'package:crypto/crypto.dart';
import 'package:http/http.dart' as http;
import 'package:intl/intl.dart';
import '../config/env_config.dart';

class S3UploadService {
  final String _accessKey = EnvConfig.awsAccessKeyId;
  final String _secretKey = EnvConfig.awsSecretAccessKey;
  final String _region = EnvConfig.awsRegion;
  final String _bucket = EnvConfig.awsBucketName;

  Future<String> uploadFile(File file, String fileName) async {
    final sanitizedFileName = _sanitizeFileName(fileName);
    final endpoint =
        'https://$_bucket.s3.$_region.amazonaws.com/$sanitizedFileName';
    final fileBytes = await file.readAsBytes();
    final contentType = _getContentType(sanitizedFileName);

    final now = DateTime.now().toUtc();
    final dateStamp = DateFormat('yyyyMMdd').format(now);
    final amzDate = DateFormat("yyyyMMdd'T'HHmmss'Z'").format(now);
    final payloadHash = sha256.convert(fileBytes).toString();

    final credentialScope = '$dateStamp/$_region/s3/aws4_request';
    final credential = '$_accessKey/$credentialScope';

    final canonicalHeaders = 'content-type:$contentType\n'
        'host:$_bucket.s3.$_region.amazonaws.com\n'
        'x-amz-content-sha256:$payloadHash\n'
        'x-amz-date:$amzDate\n';

    final signedHeaders =
        'content-type;host;x-amz-content-sha256;x-amz-date';

    final canonicalRequest = 'PUT\n'
        '/${Uri.encodeComponent(sanitizedFileName)}\n'
        '\n'
        '$canonicalHeaders\n'
        '$signedHeaders\n'
        '$payloadHash';

    final stringToSign = 'AWS4-HMAC-SHA256\n'
        '$amzDate\n'
        '$credentialScope\n'
        '${sha256.convert(utf8.encode(canonicalRequest))}';

    final signingKey = _getSignatureKey(dateStamp);
    final signature = Hmac(sha256, signingKey)
        .convert(utf8.encode(stringToSign))
        .toString();

    final authorization = 'AWS4-HMAC-SHA256 '
        'Credential=$credential, '
        'SignedHeaders=$signedHeaders, '
        'Signature=$signature';

    final response = await http.put(
      Uri.parse(endpoint),
      headers: {
        'Authorization': authorization,
        'Content-Type': contentType,
        'x-amz-content-sha256': payloadHash,
        'x-amz-date': amzDate,
      },
      body: fileBytes,
    );

    if (response.statusCode == 200 || response.statusCode == 201) {
      return endpoint;
    } else {
      throw S3UploadException(
        'Upload failed: ${response.statusCode} - ${response.body}',
      );
    }
  }

  List<int> _getSignatureKey(String dateStamp) {
    final kDate = Hmac(sha256, utf8.encode('AWS4$_secretKey'))
        .convert(utf8.encode(dateStamp))
        .bytes;
    final kRegion =
        Hmac(sha256, kDate).convert(utf8.encode(_region)).bytes;
    final kService =
        Hmac(sha256, kRegion).convert(utf8.encode('s3')).bytes;
    final kSigning = Hmac(sha256, kService)
        .convert(utf8.encode('aws4_request'))
        .bytes;
    return kSigning;
  }

  String _sanitizeFileName(String fileName) {
    return fileName.replaceAll(RegExp(r'[^a-zA-Z0-9._-]'), '_');
  }

  String _getContentType(String fileName) {
    final ext = fileName.split('.').last.toLowerCase();
    switch (ext) {
      case 'jpg':
      case 'jpeg':
        return 'image/jpeg';
      case 'png':
        return 'image/png';
      case 'gif':
        return 'image/gif';
      case 'webp':
        return 'image/webp';
      default:
        return 'application/octet-stream';
    }
  }
}

class S3UploadException implements Exception {
  final String message;
  S3UploadException(this.message);

  @override
  String toString() => 'S3UploadException: $message';
}

// lib/services/vision_service.dart
import 'dart:convert';
import 'dart:io';
import 'package:http/http.dart' as http;
import '../config/env_config.dart';

class VisionAnalysisResult {
  final List<LabelAnnotation> labels;
  final List<FaceAnnotation> faces;
  final List<TextAnnotation> texts;
  final SafeSearchAnnotation? safeSearch;
  final List<ColorInfo> dominantColors;

  VisionAnalysisResult({
    required this.labels,
    required this.faces,
    required this.texts,
    this.safeSearch,
    required this.dominantColors,
  });

  factory VisionAnalysisResult.fromJson(Map<String, dynamic> json) {
    final response = json['responses']?[0] ?? {};

    return VisionAnalysisResult(
      labels: (response['labelAnnotations'] as List<dynamic>? ?? [])
          .map((l) => LabelAnnotation.fromJson(l))
          .toList(),
      faces: (response['faceAnnotations'] as List<dynamic>? ?? [])
          .map((f) => FaceAnnotation.fromJson(f))
          .toList(),
      texts: (response['textAnnotations'] as List<dynamic>? ?? [])
          .map((t) => TextAnnotation.fromJson(t))
          .toList(),
      safeSearch: response['safeSearchAnnotation'] != null
          ? SafeSearchAnnotation.fromJson(
              response['safeSearchAnnotation'])
          : null,
      dominantColors: _extractColors(response),
    );
  }

  static List<ColorInfo> _extractColors(Map<String, dynamic> response) {
    final props = response['imagePropertiesAnnotation'];
    if (props == null) return [];
    final colors =
        props['dominantColors']?['colors'] as List<dynamic>? ?? [];
    return colors.map((c) => ColorInfo.fromJson(c)).toList();
  }
}

class LabelAnnotation {
  final String description;
  final double score;

  LabelAnnotation({required this.description, required this.score});

  factory LabelAnnotation.fromJson(Map<String, dynamic> json) {
    return LabelAnnotation(
      description: json['description'] ?? '',
      score: (json['score'] ?? 0.0).toDouble(),
    );
  }
}

class FaceAnnotation {
  final String joyLikelihood;
  final String sorrowLikelihood;
  final String angerLikelihood;
  final String surpriseLikelihood;
  final double detectionConfidence;

  FaceAnnotation({
    required this.joyLikelihood,
    required this.sorrowLikelihood,
    required this.angerLikelihood,
    required this.surpriseLikelihood,
    required this.detectionConfidence,
  });

  factory FaceAnnotation.fromJson(Map<String, dynamic> json) {
    return FaceAnnotation(
      joyLikelihood: json['joyLikelihood'] ?? 'UNKNOWN',
      sorrowLikelihood: json['sorrowLikelihood'] ?? 'UNKNOWN',
      angerLikelihood: json['angerLikelihood'] ?? 'UNKNOWN',
      surpriseLikelihood: json['surpriseLikelihood'] ?? 'UNKNOWN',
      detectionConfidence:
          (json['detectionConfidence'] ?? 0.0).toDouble(),
    );
  }
}

class TextAnnotation {
  final String description;
  final String locale;

  TextAnnotation({required this.description, this.locale = ''});

  factory TextAnnotation.fromJson(Map<String, dynamic> json) {
    return TextAnnotation(
      description: json['description'] ?? '',
      locale: json['locale'] ?? '',
    );
  }
}

class SafeSearchAnnotation {
  final String adult;
  final String violence;
  final String racy;

  SafeSearchAnnotation({
    required this.adult,
    required this.violence,
    required this.racy,
  });

  factory SafeSearchAnnotation.fromJson(Map<String, dynamic> json) {
    return SafeSearchAnnotation(
      adult: json['adult'] ?? 'UNKNOWN',
      violence: json['violence'] ?? 'UNKNOWN',
      racy: json['racy'] ?? 'UNKNOWN',
    );
  }
}

class ColorInfo {
  final int red;
  final int green;
  final int blue;
  final double score;
  final double pixelFraction;

  ColorInfo({
    required this.red,
    required this.green,
    required this.blue,
    required this.score,
    required this.pixelFraction,
  });

  factory ColorInfo.fromJson(Map<String, dynamic> json) {
    final color = json['color'] ?? {};
    return ColorInfo(
      red: (color['red'] ?? 0).toInt(),
      green: (color['green'] ?? 0).toInt(),
      blue: (color['blue'] ?? 0).toInt(),
      score: (json['score'] ?? 0.0).toDouble(),
      pixelFraction: (json['pixelFraction'] ?? 0.0).toDouble(),
    );
  }
}

class VisionService {
  static const String _baseUrl =
      'https://vision.googleapis.com/v1/images:annotate';
  static const int _maxImageSizeBytes = 10 * 1024 * 1024; // 10MB

  final String _apiKey = EnvConfig.googleCloudVisionApiKey;

  Future<VisionAnalysisResult> analyzeImage(File imageFile) async {
    final fileSize = await imageFile.length();
    if (fileSize > _maxImageSizeBytes) {
      throw VisionServiceException(
        'Image too large. Maximum size is 10MB.',
      );
    }

    final bytes = await imageFile.readAsBytes();
    final base64Image = base64Encode(bytes);

    final requestBody = {
      'requests': [
        {
          'image': {'content': base64Image},
          'features': [
            {'type': 'LABEL_DETECTION', 'maxResults': 15},
            {'type': 'FACE_DETECTION', 'maxResults': 10},
            {'type': 'TEXT_DETECTION', 'maxResults': 10},
            {'type': 'SAFE_SEARCH_DETECTION'},
            {'type': 'IMAGE_PROPERTIES'},
          ],
        }
      ],
    };

    final response = await http
        .post(
          Uri.parse('$_baseUrl?key=$_apiKey'),
          headers: {'Content-Type': 'application/json'},
          body: jsonEncode(requestBody),
        )
        .timeout(const Duration(seconds: 30));

    if (response.statusCode == 200) {
      final jsonResponse = jsonDecode(response.body);

      if (jsonResponse['responses']?[0]?['error'] != null) {
        throw VisionServiceException(
          'Vision API error: ${jsonResponse['responses'][0]['error']['message']}',
        );
      }

      return VisionAnalysisResult.fromJson(jsonResponse);
    } else {
      throw VisionServiceException(
        'Vision API request failed: ${response.statusCode}',
      );
    }
  }
}

class VisionServiceException implements Exception {
  final String message;
  VisionServiceException(this.message);

  @override
  String toString() => 'VisionServiceException: $message';
}

