  Widget _buildActionButtons() {
    return Wrap(
      spacing: 8,
      runSpacing: 8,
      alignment: WrapAlignment.center,
      children: [
        FilledButton.icon(
          onPressed:
              _isUploading || _isAnalyzing ? null : _pickFromGallery,
          icon: const Icon(Icons.photo_library),
          label: const Text('Gallery'),
