                    '${l.description} (${(l.score * 100).toStringAsFixed(1)}%)')
                .toList(),
          ),
        if (result.faces.isNotEmpty) ...[
          const SizedBox(height: 8),
          _buildSectionCard(
            'Faces Detected: ${result.faces.length}',
            Icons.face,
            result.faces
                .asMap()
