      ),
    );
  }

  Widget _buildColorCard(List<ColorInfo> colors) {
    final topColors = colors.take(6).toList();
    return Card(
      child: Padding(
        padding: const EdgeInsets.all(16),
        child: Column(
          crossAxisAlignment: CrossAxisAlignment.start,
          children: [
            const Row(
              children: [
                Icon(Icons.palette, size: 20),
                SizedBox(width: 8),
                Text('Dominant Colors',
                    style: TextStyle(
                        fontWeight: FontWeight.bold, fontSize: 16)),
              ],
            ),
            const SizedBox(height: 12),
            Wrap(
              spacing: 8,
              runSpacing: 8,
              children: topColors
                  .map((c) => Container(
                        width: 48,
                        height: 48,
                        decoration: BoxDecoration(
                          color:
                              Color.fromRGBO(c.red, c.green, c.blue, 1),
                          borderRadius: BorderRadius.circular(8),
                          border: Border.all(
                              color: Colors.grey.shade300),
